USE [DeineDatenbank];
GO

/*
===============================================================================
Objekt       : monitor.USP_QueryStoreForcedPlans
Version      : 2.0.0
Stand        : 2026-07-15
Zweck        : Liefert erzwungene Query-Store-Pläne aus mehreren
               Quelldatenbanken mit globaler Top-N-Ausgabe und optionalem
               Referenzdatenbankfilter.
===============================================================================
*/
CREATE OR ALTER PROCEDURE [monitor].[USP_QueryStoreForcedPlans]
      @QueryStoreDatabaseNames          nvarchar(max)  = NULL
    , @QueryStoreDatabaseNamePattern    nvarchar(4000) = NULL
    , @HighImpactConfirmed              bit            = 0
    , @ReferencedDatabaseNames          nvarchar(max)  = NULL
    , @ReferencedDatabaseNamePattern    nvarchar(4000) = NULL
    , @QueryId                          bigint         = NULL
    , @NurMitFehler                     bit            = 0
    , @MitPlanXml                       bit            = 0
    , @MaxZeilen                        int            = 100
    , @MaxSqlTextZeichen                int            = 4000
    , @ResultSetArt                     varchar(16)    = 'CONSOLE'
    , @ResultTablesJson               nvarchar(max) = NULL
    , @JsonErzeugen                     bit            = 0
    , @Json                             nvarchar(max)  = NULL OUTPUT
    , @PrintMeldungen                   bit            = 1
    , @Hilfe                            bit            = 0
AS
BEGIN
 SET NOCOUNT ON;SET @Json=NULL;DECLARE @Out varchar(16)=UPPER(LTRIM(RTRIM(COALESCE(@ResultSetArt,'')))),@Limit bigint=CASE WHEN @MaxZeilen IS NULL OR @MaxZeilen=0 THEN CONVERT(bigint,9223372036854775807) WHEN @MaxZeilen>0 THEN @MaxZeilen ELSE 0 END,@Local bigint=CASE WHEN @MaxZeilen IS NULL OR @MaxZeilen=0 THEN CONVERT(bigint,9223372036854775807) WHEN @MaxZeilen<2147483647 THEN CONVERT(bigint,@MaxZeilen)+1 ELSE @MaxZeilen END;
    DECLARE @TableResultRequested bit = CASE WHEN @Out = 'TABLE' THEN 1 ELSE 0 END;
    DECLARE @ConsoleResultRequested bit = CASE WHEN @Out = 'CONSOLE' THEN 1 ELSE 0 END;
    DECLARE @TableTarget sysname=NULL;
    IF @TableResultRequested=0 AND NULLIF(LTRIM(RTRIM(COALESCE(@ResultTablesJson,N''))),N'') IS NOT NULL THROW 51011,N'@ResultTablesJson ist ausschließlich mit @ResultSetArt=TABLE zulässig.',1;
    IF @TableResultRequested=1 EXEC [monitor].[InternalPrepareSingleResultTable] @ResultTablesJson=@ResultTablesJson,@ResultName=N'forcedPlans',@TargetTable=@TableTarget OUTPUT,@ThrowOnError=1;
    IF @TableResultRequested = 1 OR @ConsoleResultRequested = 1 SET @Out = 'NONE';
 IF @Hilfe=1 BEGIN PRINT N'monitor.USP_QueryStoreForcedPlans';PRINT N'Quell-DB-Liste/Pattern, Referenz-DB-Liste/Pattern, RAW|CONSOLE|TABLE|NONE und JSON.';RETURN;END;
 DECLARE @Now datetime2(3)=SYSUTCDATETIME(),@Status varchar(40)='AVAILABLE',@Partial bit=0,@Error nvarchar(2048)=NULL,@Cross bit=0,@Allowed bit=1,@Db sysname,@Compat tinyint,@Sql nvarchar(max),@Count bigint=0,@HasMore bit=0,@Msg nvarchar(2048),@RefMode varchar(8),@RefValue nvarchar(4000),@RefFlags varchar(8),@RefValid bit,@RefPredicate nvarchar(max)=N'';
 SELECT @RefMode=[PatternMode],@RefValue=[PatternValue],@RefFlags=[RegexFlags],@RefValid=[IsValid] FROM [monitor].[TVF_ParsePattern](@ReferencedDatabaseNamePattern);
 CREATE TABLE [#QueryStoreForcedPlans_DatabaseCandidates]([DatabaseId] int NOT NULL,[DatabaseName] sysname NOT NULL,[StateDesc] nvarchar(60),[UserAccessDesc] nvarchar(60),[IsReadOnly] bit,[CompatibilityLevel] tinyint,[CollationName] sysname,[RecoveryModelDesc] nvarchar(60),[IsSystemDatabase] bit,[RequestedOrdinal] int);
 CREATE TABLE [#QueryStoreForcedPlans_Result]([QueryStoreDatabaseId] int,[QueryStoreDatabaseName] sysname,[QueryId] bigint,[PlanId] bigint,[QueryHash] binary(8),[QueryPlanHash] binary(8),[ObjectId] bigint NULL,[ObjectName] nvarchar(517) NULL,[IsForcedPlan] bit,[PlanForcingTypeDesc] nvarchar(60),[ForceFailureCount] bigint,[LastForceFailureReason] int,[LastForceFailureReasonDesc] nvarchar(128),[CountCompiles] bigint,[LastCompileStartTimeUtc] datetimeoffset,[LastExecutionTimeUtc] datetimeoffset,[EngineVersion] nvarchar(32),[CompatibilityLevel] smallint,[QuerySqlText] nvarchar(max),[QueryPlanTextFallback] nvarchar(max) NULL,[SourceType] varchar(32) NULL,[SourceObject] nvarchar(256) NULL,[CapturedAtUtc] datetime2(3) NULL,[EvidenceScope] varchar(40) NULL,[QuerySqlTextCharacters] bigint NULL,[QuerySqlTextBytes] bigint NULL,[QuerySqlTextIsTruncated] bit NULL,[QueryPlanStatus] varchar(40) NULL,[QueryPlanCharacters] bigint NULL,[QueryPlanBytes] bigint NULL,[QueryPlan] xml NULL,[EvidenceLimit] nvarchar(1000) NULL);
 CREATE TABLE [#QueryStoreForcedPlans_Errors]([DatabaseName] sysname,[StatusCode] varchar(40),[ErrorNumber] int NULL,[ErrorMessage] nvarchar(2048));
 IF @MaxZeilen<0 OR @MaxSqlTextZeichen < 0 OR @Out NOT IN('RAW','CONSOLE','NONE') OR @RefValid=0 OR (@ReferencedDatabaseNames IS NOT NULL AND @ReferencedDatabaseNamePattern IS NOT NULL) OR (@ReferencedDatabaseNames IS NOT NULL AND EXISTS(SELECT 1 FROM [monitor].[TVF_ParseSqlNameList](@ReferencedDatabaseNames) WHERE [IsValid]=0)) BEGIN SET @Status='INVALID_PARAMETER';SET @Error=N'Ungültiger Parameter.';END;
 IF @Status='AVAILABLE' EXEC [monitor].[USP_PrepareDatabaseCandidates] @DatabaseNames=@QueryStoreDatabaseNames,@SystemdatenbankenEinbeziehen=0,@DatabaseNamePattern=@QueryStoreDatabaseNamePattern,@HighImpactConfirmed=@HighImpactConfirmed,@AnalysisClass='QUERY_STORE_CURRENT',@StatusCode=@Status OUTPUT,@ErrorMessage=@Error OUTPUT,@CrossDatabaseRequested=@Cross OUTPUT,@CandidateTable=N'#QueryStoreForcedPlans_DatabaseCandidates';
 IF @Status='AVAILABLE' AND (@MitPlanXml=1 OR @Limit>1000 OR @ReferencedDatabaseNames IS NOT NULL OR @ReferencedDatabaseNamePattern IS NOT NULL) EXEC [monitor].[InternalCheckAnalysisPath] @AnalysisClass='QUERY_STORE_DEEP',@HighImpactConfirmed=@HighImpactConfirmed,@StatusCode=@Status OUTPUT,@ErrorMessage=@Error OUTPUT;
 IF @ReferencedDatabaseNames IS NOT NULL SET @RefPredicate=N' AND EXISTS(SELECT 1 FROM (SELECT CONVERT(xml,[p].[query_plan]) [PlanXml]) [px] CROSS APPLY [px].[PlanXml].nodes(''declare default element namespace "http://schemas.microsoft.com/sqlserver/2004/07/showplan"; //Object[@Database]'') [n]([x]) JOIN [monitor].[TVF_ParseSqlNameList](@ReferencedNames) [rf] ON [rf].[IsValid]=1 AND [rf].[NameValue] COLLATE SQL_Latin1_General_CP1_CS_AS=PARSENAME([n].[x].value(''@Database'',''nvarchar(776)''),1) COLLATE SQL_Latin1_General_CP1_CS_AS)';
 ELSE IF @RefMode='LIKE' SET @RefPredicate=N' AND EXISTS(SELECT 1 FROM (SELECT CONVERT(xml,[p].[query_plan]) [PlanXml]) [px] CROSS APPLY [px].[PlanXml].nodes(''declare default element namespace "http://schemas.microsoft.com/sqlserver/2004/07/showplan"; //Object[@Database]'') [n]([x]) WHERE PARSENAME([n].[x].value(''@Database'',''nvarchar(776)''),1) COLLATE SQL_Latin1_General_CP1_CS_AS LIKE @RefValue COLLATE SQL_Latin1_General_CP1_CS_AS)';
 ELSE IF @RefMode IN('REGEX','REGEXI') SET @RefPredicate=N' AND EXISTS(SELECT 1 FROM (SELECT CONVERT(xml,[p].[query_plan]) [PlanXml]) [px] CROSS APPLY [px].[PlanXml].nodes(''declare default element namespace "http://schemas.microsoft.com/sqlserver/2004/07/showplan"; //Object[@Database]'') [n]([x]) WHERE REGEXP_LIKE(PARSENAME([n].[x].value(''@Database'',''nvarchar(776)''),1),@RefValue,@RefFlags))';
 SET LOCK_TIMEOUT 0;
 IF @Status='AVAILABLE' BEGIN DECLARE [c] CURSOR LOCAL FAST_FORWARD FOR SELECT [DatabaseName],[CompatibilityLevel] FROM [#QueryStoreForcedPlans_DatabaseCandidates] ORDER BY COALESCE([RequestedOrdinal],[DatabaseId]),[DatabaseId];OPEN [c];FETCH NEXT FROM [c] INTO @Db,@Compat;WHILE @@FETCH_STATUS=0 BEGIN IF @RefMode IN('REGEX','REGEXI') AND (TRY_CONVERT(int,SERVERPROPERTY(N'ProductMajorVersion'))<17 OR @Compat<170) BEGIN INSERT [#QueryStoreForcedPlans_Errors] VALUES(@Db,'UNAVAILABLE_FEATURE',NULL,N'Regex benötigt SQL Server 2025 und Compatibility Level 170.');SET @Partial=1;END ELSE BEGIN TRY SET @Sql=N'USE '+QUOTENAME(@Db)+N';IF EXISTS(SELECT 1 FROM [sys].[database_query_store_options] WITH (NOLOCK) WHERE [actual_state] IN(1,2,4)) INSERT [#QueryStoreForcedPlans_Result] ([QueryStoreDatabaseId],[QueryStoreDatabaseName],[QueryId],[PlanId],[QueryHash],[QueryPlanHash],[ObjectId],[ObjectName],[IsForcedPlan],[PlanForcingTypeDesc],[ForceFailureCount],[LastForceFailureReason],[LastForceFailureReasonDesc],[CountCompiles],[LastCompileStartTimeUtc],[LastExecutionTimeUtc],[EngineVersion],[CompatibilityLevel],[QuerySqlText],[QueryPlanTextFallback]) SELECT TOP(@TopRows) DB_ID(),(SELECT [name] FROM [master].[sys].[databases] WITH (NOLOCK) WHERE [database_id] = DB_ID()),[q].[query_id],[p].[plan_id],[q].[query_hash],[p].[query_plan_hash],[q].[object_id],CASE WHEN [q].[object_id]>0 THEN QUOTENAME([os].[name])+N''.''+QUOTENAME([oo].[name]) END,[p].[is_forced_plan],[p].[plan_forcing_type_desc],[p].[force_failure_count],[p].[last_force_failure_reason],[p].[last_force_failure_reason_desc],[p].[count_compiles],[p].[last_compile_start_time],[p].[last_execution_time],[p].[engine_version],[p].[compatibility_level],[qt].[query_sql_text],CASE WHEN @IncludePlan=1 THEN [p].[query_plan] END FROM [sys].[query_store_plan] [p] WITH (NOLOCK) JOIN [sys].[query_store_query] [q] WITH (NOLOCK) ON [q].[query_id]=[p].[query_id] JOIN [sys].[query_store_query_text] [qt] WITH (NOLOCK) ON [qt].[query_text_id]=[q].[query_text_id] LEFT JOIN [sys].[objects] [oo] WITH (NOLOCK) ON [oo].[object_id]=[q].[object_id] LEFT JOIN [sys].[schemas] [os] WITH (NOLOCK) ON [os].[schema_id]=[oo].[schema_id] WHERE [p].[is_forced_plan]=1 AND (@QueryId IS NULL OR [q].[query_id]=@QueryId) AND (@OnlyErrors=0 OR [p].[force_failure_count]>0 OR [p].[last_force_failure_reason]<>0)'+@RefPredicate+N' ORDER BY CASE WHEN [p].[last_force_failure_reason]<>0 THEN 0 ELSE 1 END,[p].[last_execution_time] DESC;';EXEC [sys].[sp_executesql] @Sql,N'@TopRows bigint,@QueryId bigint,@OnlyErrors bit,@IncludePlan bit,@ReferencedNames nvarchar(max),@RefValue nvarchar(4000),@RefFlags varchar(8)',@Local,@QueryId,@NurMitFehler,@MitPlanXml,@ReferencedDatabaseNames,@RefValue,@RefFlags;END TRY BEGIN CATCH INSERT [#QueryStoreForcedPlans_Errors] VALUES(@Db,CASE WHEN ERROR_NUMBER() IN(229,262,297,300,371,916) THEN 'DENIED_PERMISSION' WHEN ERROR_NUMBER()=1222 THEN 'TIMEOUT' ELSE 'ERROR_HANDLED' END,ERROR_NUMBER(),ERROR_MESSAGE());SET @Partial=1;IF @PrintMeldungen=1 BEGIN SET @Msg=FORMATMESSAGE(N'WARNUNG USP_QueryStoreForcedPlans [%s]: %s',@Db,ERROR_MESSAGE());RAISERROR(N'%s',10,1,@Msg) WITH NOWAIT;END;END CATCH;FETCH NEXT FROM [c] INTO @Db,@Compat;END;CLOSE [c];DEALLOCATE [c];END;
 UPDATE [r] SET [SourceType]='QUERY_STORE',[SourceObject]=N'sys.query_store_plan|sys.query_store_query_text',[CapturedAtUtc]=@Now,[EvidenceScope]='DATABASE_QUERY_PLAN',[QuerySqlTextCharacters]=[p].[OriginalCharacters],[QuerySqlTextBytes]=[p].[OriginalBytes],[QuerySqlTextIsTruncated]=[p].[IsTruncated],[QuerySqlText]=[p].[ProjectedValue],[QueryPlanStatus]=CASE WHEN @MitPlanXml=0 THEN 'NOT_REQUESTED' ELSE 'PENDING' END,[EvidenceLimit]=N'Gespeicherter Query-Store-Plan und aggregierte Metadaten; kein aktueller Ausführungsplan.' FROM [#QueryStoreForcedPlans_Result] [r] CROSS APPLY [monitor].[TVF_ProjectUnicodeText]([r].[QuerySqlText],@MaxSqlTextZeichen) [p];
 DECLARE @PlanDb int,@PlanQuery bigint,@PlanIdLocal bigint,@PlanText nvarchar(max),@PlanXml xml,@PlanStatus varchar(40),@PlanErr int,@PlanMsg nvarchar(2048);DECLARE [pc] CURSOR LOCAL FAST_FORWARD FOR SELECT [QueryStoreDatabaseId],[QueryId],[PlanId],[QueryPlanTextFallback] FROM [#QueryStoreForcedPlans_Result] WHERE @MitPlanXml=1;OPEN [pc];FETCH NEXT FROM [pc] INTO @PlanDb,@PlanQuery,@PlanIdLocal,@PlanText;WHILE @@FETCH_STATUS=0 BEGIN EXEC [monitor].[InternalParseXmlText] @XmlText=@PlanText,@XmlValue=@PlanXml OUTPUT,@StatusCode=@PlanStatus OUTPUT,@ErrorNumber=@PlanErr OUTPUT,@ErrorMessage=@PlanMsg OUTPUT;UPDATE [#QueryStoreForcedPlans_Result] SET [QueryPlanStatus]=@PlanStatus,[QueryPlanCharacters]=CASE WHEN @PlanText IS NULL THEN NULL ELSE CONVERT(bigint,LEN((@PlanText+NCHAR(1)) COLLATE Latin1_General_100_CI_AS_SC)-1) END,[QueryPlanBytes]=CONVERT(bigint,DATALENGTH(@PlanText)),[QueryPlan]=@PlanXml,[QueryPlanTextFallback]=CASE WHEN @PlanStatus IN('AVAILABLE','XML_EMPTY','SOURCE_NULL') THEN NULL ELSE @PlanText END WHERE [QueryStoreDatabaseId]=@PlanDb AND [QueryId]=@PlanQuery AND [PlanId]=@PlanIdLocal;IF @PlanStatus IN('XML_INVALID','XML_UNAVAILABLE_LIMIT') BEGIN INSERT [#QueryStoreForcedPlans_Errors] VALUES((SELECT TOP(1) [QueryStoreDatabaseName] FROM [#QueryStoreForcedPlans_Result] WHERE [QueryStoreDatabaseId]=@PlanDb),@PlanStatus,@PlanErr,@PlanMsg);SET @Partial=1;END;FETCH NEXT FROM [pc] INTO @PlanDb,@PlanQuery,@PlanIdLocal,@PlanText;END;CLOSE [pc];DEALLOCATE [pc];
 DECLARE @TruncatedValueCount bigint=0,@LargestRequiredCharacters bigint=NULL;SELECT @TruncatedValueCount=COUNT_BIG(*),@LargestRequiredCharacters=MAX([QuerySqlTextCharacters]) FROM [#QueryStoreForcedPlans_Result] WHERE [QuerySqlTextIsTruncated]=1;EXEC [monitor].[InternalEmitTruncationWarning] @TruncatedValueCount=@TruncatedValueCount,@ParameterName=N'@MaxSqlTextZeichen',@ParameterValue=@MaxSqlTextZeichen,@LargestRequiredCharacters=@LargestRequiredCharacters,@PrintMeldungen=@PrintMeldungen;
 SELECT @Count=COUNT_BIG(*) FROM [#QueryStoreForcedPlans_Result];SET @HasMore=CONVERT(bit,CASE WHEN @Limit<9223372036854775807 AND @Count>@Limit THEN 1 ELSE 0 END);IF @Partial=1 AND @Status='AVAILABLE' SET @Status='AVAILABLE_LIMITED';
 IF @Out<>'NONE' BEGIN SELECT N'USP_QueryStoreForcedPlans' [ModuleName],@Now [CollectionTimeUtc],@Status [StatusCode],@Partial [IsPartial],CASE WHEN @Count>@Limit THEN @Limit ELSE @Count END [ReturnedRowCount],@HasMore [HasMoreRows],@Error [ErrorMessage];IF @Out='RAW' SELECT TOP(@Limit) * FROM [#QueryStoreForcedPlans_Result] ORDER BY CASE WHEN [LastForceFailureReason]<>0 THEN 0 ELSE 1 END,[LastExecutionTimeUtc] DESC;ELSE SELECT TOP(@Limit) N'Erzwungener Query-Store-Plan' [Ergebnis],[QueryStoreDatabaseName] [Query-Store-Datenbank],[QueryId] [Query],[PlanId] [Plan],[LastForceFailureReasonDesc] [letzter Fehler],[ForceFailureCount] [Fehleranzahl],[LastExecutionTimeUtc] [letzte Ausführung],[QueryStoreDatabaseName] [Quelle],[QuerySqlText] [SQL-Text],[QueryPlan] [Plan-XML] FROM [#QueryStoreForcedPlans_Result] ORDER BY CASE WHEN [LastForceFailureReason]<>0 THEN 0 ELSE 1 END,[LastExecutionTimeUtc] DESC;SELECT * FROM [#QueryStoreForcedPlans_Errors] ORDER BY [DatabaseName];END;
 IF @JsonErzeugen=1 BEGIN DECLARE @Meta nvarchar(max)=(SELECT N'QueryStoreForcedPlans' [resultName],2 [schemaVersion],@Now [generatedAtUtc],@Status [statusCode],@MaxZeilen [requestedMaxRows],CASE WHEN @Count>@Limit THEN @Limit ELSE @Count END [returnedRows],@HasMore [hasMoreRows] FOR JSON PATH,WITHOUT_ARRAY_WRAPPER,INCLUDE_NULL_VALUES),@Data nvarchar(max)=(SELECT TOP(@Limit) [QueryStoreDatabaseId],[QueryStoreDatabaseName],[QueryId],[PlanId],[QueryHash],[QueryPlanHash],[ObjectId],[ObjectName],[IsForcedPlan],[PlanForcingTypeDesc],[ForceFailureCount],[LastForceFailureReason],[LastForceFailureReasonDesc],[CountCompiles],[LastCompileStartTimeUtc],[LastExecutionTimeUtc],[EngineVersion],[CompatibilityLevel],[QuerySqlText],[QueryPlanTextFallback],[SourceType],[SourceObject],[CapturedAtUtc],[EvidenceScope],[QuerySqlTextCharacters],[QuerySqlTextBytes],[QuerySqlTextIsTruncated],[QueryPlanStatus],[QueryPlanCharacters],[QueryPlanBytes],CONVERT(nvarchar(max),[QueryPlan]) [QueryPlan],[EvidenceLimit] FROM [#QueryStoreForcedPlans_Result] ORDER BY CASE WHEN [LastForceFailureReason]<>0 THEN 0 ELSE 1 END,[LastExecutionTimeUtc] DESC FOR JSON PATH,INCLUDE_NULL_VALUES),@Warnings nvarchar(max)=(SELECT * FROM [#QueryStoreForcedPlans_Errors] ORDER BY [DatabaseName] FOR JSON PATH,INCLUDE_NULL_VALUES);SET @Json=CONCAT(N'{"meta":',COALESCE(@Meta,N'{}'),N',"forcedPlans":',COALESCE(@Data,N'[]'),N',"warnings":',COALESCE(@Warnings,N'[]'),N'}');END;
    IF @ConsoleResultRequested = 1
    BEGIN
        EXEC [monitor].[InternalEmitConsoleResult]
              @SourceTable=N'#QueryStoreForcedPlans_Result'
            , @ResultLabel=N'QueryStoreForcedPlans'
            , @EmptyMessage=N'Keine fachlichen Ergebnisse';
    END;
    IF @TableResultRequested = 1
    BEGIN
        EXEC [monitor].[InternalWriteResultTable]
              @SourceTable = N'#QueryStoreForcedPlans_Result'
            , @TargetTable=@TableTarget
            , @ThrowOnError = 1;
    END;
END;
GO
